	     output wire       g,

	     input wire        clk,
	     input wire        rst);reg [3:0] 		       ra;
   reg [3:0] 		       rb;

   wire [3:0] 		       ra_next;
   wire [3:0] 		       rb_next;

   assign ra_next = c1 ? a :
		    c2 ? (ra - rb) :
		    ra;

